// ============================================================
// JSONKB v1 — VEHICLES (compact metadata, only emit TRUE flags)
// Inputs (by node name):
// - Vehicle – Detail
// ============================================================

// Pull vehicle detail row
const vItems = $items("Vehicle – Detail");
if (!vItems || vItems.length === 0) {
  throw new Error('JSONKB Vehicles: Missing input from node "Vehicle – Detail".');
}
const row = vItems[0].json;


// ---------- helpers ----------
function cleanBool(v) {
  if (v === true || v === 1 || v === '1' || String(v).toLowerCase() === 'true') return true;
  return false;
}

function stableStringify(value) {
  const seen = new WeakSet();

  function norm(v) {
    if (v === null || v === undefined) return v;

    if (typeof v === 'object') {
      if (seen.has(v)) return null; // defensive; shouldn’t happen
      seen.add(v);

      if (Array.isArray(v)) return v.map(norm); // keep array order

      const out = {};
      for (const k of Object.keys(v).sort()) out[k] = norm(v[k]);
      return out;
    }

    return v;
  }

  return JSON.stringify(norm(value));
}

function slugify(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');
}

function asNum(x) {
  if (x === null || x === undefined || x === '') return null;
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
}

function asInt(x) {
  const n = asNum(x);
  return Number.isFinite(n) ? Math.trunc(n) : null;
}

function asBool01(x) {
  if (x === null || x === undefined) return null;
  const n = Number(x);
  if (!Number.isNaN(n)) return n !== 0;
  const s = String(x).toLowerCase();
  if (['true','t','yes','y','1'].includes(s)) return true;
  if (['false','f','no','n','0'].includes(s)) return false;
  return null;
}

function pickUrl(x) {
  const s = String(x || '').trim();
  return s ? s : null;
}

function compactObj(obj) {
  // remove null/undefined/empty objects
  if (!obj || typeof obj !== 'object') return obj;
  const out = Array.isArray(obj) ? [] : {};
  for (const [k, v] of Object.entries(obj)) {
    if (v === null || v === undefined) continue;
    if (typeof v === 'object' && !Array.isArray(v)) {
      const inner = compactObj(v);
      if (inner && Object.keys(inner).length) out[k] = inner;
      continue;
    }
    if (Array.isArray(v)) {
      if (v.length) out[k] = v;
      continue;
    }
    out[k] = v;
  }
  return out;
}

function onlyTrueFlags(obj) {
  // keep ONLY keys whose value is === true
  const out = {};
  for (const [k, v] of Object.entries(obj || {})) {
    if (v === true) out[k] = true;
  }
  return out;
}

function parseContainerSizes(v) {
  const valid = new Set([1,2,4,8,16,24,32]);
  const src = (v ?? '').toString();
  if (!src.trim()) return [];
  return src.split(',')
    .map(s => Number(s.trim()))
    .filter(n => Number.isInteger(n) && valid.has(n))
    .sort((a,b) => a - b);
}

// ---------- slug ----------
const slug = slugify(row.slug || row.name);
if (!slug) throw new Error('JSONKB Vehicles: slug is empty.');


const kb_links = {
  kb_page_path: `/kb/${slug}`,
  kb_browse_path: `/browse?category=vehicle`,
};

// ---------- deterministic kb_text ----------
const name = row.name || 'Unknown Vehicle';
const manufacturer = row.company_name || 'Unknown manufacturer';

const isGround = cleanBool(row.is_ground_vehicle);
const vehicleKind = isGround ? 'ground vehicle' : 'spacecraft';

const scu = (row.scu === null || row.scu === undefined || row.scu === '') ? 'unknown' : row.scu;
const crewMin = (row.crew_min === null || row.crew_min === undefined || row.crew_min === '') ? '?' : row.crew_min;
const crewMax = (row.crew_max === null || row.crew_max === undefined || row.crew_max === '') ? '?' : row.crew_max;

const kb_text =
  `${name} is a ${vehicleKind} manufactured by ${manufacturer}. ` +
  `It has an SCU capacity of ${scu} and supports a crew size of ${crewMin} to ${crewMax}.`;

// ---------- normalize metadata/raw ----------
// IMPORTANT:
// If you add `v.metadata->'raw' AS raw` to Vehicle–Detail SQL, you'll get row.raw.
const raw = (row.raw && typeof row.raw === 'object') ? row.raw : {};

// ---------- container sizes ----------
const containerSizes = parseContainerSizes(row.container_sizes ?? raw.container_sizes ?? '');

// ---------- flags (TRUE only) ----------
const ship_flags = onlyTrueFlags({
  is_spaceship:       asBool01(row.is_spaceship ?? raw.is_spaceship),
  is_ground_vehicle:  asBool01(row.is_ground_vehicle ?? raw.is_ground_vehicle),
  is_concept:         asBool01(row.is_concept ?? raw.is_concept),
  is_quantum_capable: asBool01(row.is_quantum_capable ?? raw.is_quantum_capable),
});

// Role flags come from your Vehicle–Detail SQL columns (is_military, etc).
// Fallback to raw.* if you later include raw.
const role_flags = onlyTrueFlags({
  is_military:    asBool01(row.is_military    ?? raw.is_military),
  is_civilian:    asBool01(row.is_civilian    ?? raw.is_civilian),
  is_industrial:  asBool01(row.is_industrial  ?? raw.is_industrial),
  is_exploration: asBool01(row.is_exploration ?? raw.is_exploration),
  is_mining:      asBool01(row.is_mining      ?? raw.is_mining),
  is_transport:   asBool01(row.is_transport   ?? raw.is_transport),
});

// Capability-ish flags: only populated if you include raw (recommended)
const capability_flags = onlyTrueFlags({
  is_cargo:        asBool01(raw.is_cargo),
  is_racing:       asBool01(raw.is_racing),
  is_tractor_beam: asBool01(raw.is_tractor_beam),
  is_interdiction: asBool01(raw.is_interdiction),
  is_medical:      asBool01(raw.is_medical),
  is_salvage:      asBool01(raw.is_salvage),
  is_refuel:       asBool01(raw.is_refuel),
  is_repair:       asBool01(raw.is_repair),
  is_science:      asBool01(raw.is_science),
  is_stealth:      asBool01(raw.is_stealth),
  is_starter:      asBool01(raw.is_starter),
});

// ---------- entity_metadata (compact) ----------
let entity_metadata = {
  uex_vehicle_id: row.uex_vehicle_id != null ? Number(row.uex_vehicle_id) : null,
  manufacturer: row.company_name || raw.company_name || null,
  name_full: (row.name_full && row.name_full !== row.name) ? row.name_full : null,

  scu_capacity: row.scu != null ? Number(row.scu) : asNum(raw.scu),
  crew_min: row.crew_min != null ? Number(row.crew_min) : asInt(raw.crew),
  crew_max: row.crew_max != null ? Number(row.crew_max) : asInt(raw.crew),
  pad_type: row.pad_type || raw.pad_type || null,

  supported_container_sizes: containerSizes,

  ship_flags: Object.keys(ship_flags).length ? ship_flags : null,
  role_flags: Object.keys(role_flags).length ? role_flags : null,
  capability_flags: Object.keys(capability_flags).length ? capability_flags : null,

  // optional: only if you include raw OR add fields to SQL
  dimensions_m: (raw.length != null || raw.width != null || raw.height != null) ? {
    length: asNum(raw.length),
    width:  asNum(raw.width),
    height: asNum(raw.height),
  } : null,

  urls: (raw.url_photo || raw.url_store || raw.url_video || raw.url_brochure || raw.url_hotsite) ? {
    uex_photo: pickUrl(raw.url_photo),
    rsi_store: pickUrl(raw.url_store),
    video:     pickUrl(raw.url_video),
    brochure:  pickUrl(raw.url_brochure),
    hotsite:   pickUrl(raw.url_hotsite),
  } : null,

  game_version: row.game_version || raw.game_version || null,
};

entity_metadata = compactObj(entity_metadata);

// ---------- rag_hints ----------
const rag_hints = {
  sql_hints: [
    {
      id: "vehicle.core",
      description: "Core vehicle fields + raw metadata.",
      params: [{"name":"vehicle_id","type":"uuid","required":true}],
      sql_template: `SELECT v.id, v.name, v.name_full, v.slug, v.company_name, v.company_uex_id, v.scu, v.crew_min, v.crew_max, v.pad_type, v.game_version, v.is_spaceship, v.is_ground_vehicle, v.is_concept, v.is_quantum_capable, v.metadata->'raw' AS raw
FROM vehicles v
WHERE v.id = :vehicle_id
LIMIT 1;`
    },
    {
      id: "vehicle.purchase_points",
      description: "Purchase locations + buy prices (aUEC).",
      params: [{"name":"vehicle_id","type":"uuid","required":true}],
      sql_template: `SELECT COALESCE((SELECT jsonb_agg(jsonb_build_object('star_system_name',vpp.star_system_name,'planet_name',vpp.planet_name,'city_name',vpp.city_name,'orbit_name',vpp.orbit_name,'terminal_name',vpp.terminal_name,'terminal_code',vpp.terminal_code,'price_buy',vpp.price_buy) ORDER BY vpp.star_system_name,vpp.planet_name,vpp.city_name,vpp.orbit_name,vpp.terminal_name) FROM vehicle_purchase_prices vpp WHERE vpp.vehicle_id = :vehicle_id AND vpp.price_buy > 0),'[]'::jsonb) AS purchase_points;`
    },
    {
      id: "vehicle.rental_points",
      description: "Rental locations + rent prices.",
      params: [{"name":"vehicle_id","type":"uuid","required":true}],
      sql_template: `SELECT COALESCE((SELECT jsonb_agg(jsonb_build_object('star_system_name',vrp.star_system_name,'planet_name',vrp.planet_name,'city_name',vrp.city_name,'orbit_name',vrp.orbit_name,'terminal_name',vrp.terminal_name,'terminal_code',vrp.terminal_code,'price_rent',vrp.price_rent) ORDER BY vrp.star_system_name,vrp.planet_name,vrp.city_name,vrp.orbit_name,vrp.terminal_name) FROM vehicle_rental_prices vrp WHERE vrp.vehicle_id = :vehicle_id AND vrp.price_rent > 0),'[]'::jsonb) AS rental_points;`
    },
    {
      id: "vehicle.store_prices",
      description: "Pledge store prices (USD/etc) by game_version.",
      params: [{"name":"vehicle_id","type":"uuid","required":true}],
      sql_template: `SELECT COALESCE((SELECT jsonb_agg(jsonb_build_object('currency',vsp.currency,'price',vsp.price,'price_package',vsp.price_package,'price_warbond',vsp.price_warbond,'price_concierge',vsp.price_concierge,'on_sale',vsp.on_sale,'on_sale_package',vsp.on_sale_package,'on_sale_warbond',vsp.on_sale_warbond,'on_sale_concierge',vsp.on_sale_concierge,'game_version',vsp.game_version) ORDER BY vsp.game_version) FROM vehicle_store_prices vsp WHERE vsp.vehicle_id = :vehicle_id AND COALESCE(vsp.price,0) > 0),'[]'::jsonb) AS store_prices;`
    },
    {
      id: "vehicle.manufacturer",
      description: "Manufacturer fields for this vehicle.",
      params: [{"name":"vehicle_id","type":"uuid","required":true}],
      sql_template: `SELECT v.company_name, v.company_uex_id
FROM vehicles v
WHERE v.id = :vehicle_id
LIMIT 1;`
    },
    {
      id: "vehicle.manufacturer_vehicles",
      description: "List vehicles by same manufacturer (company_uex_id).",
      params: [{"name":"vehicle_id","type":"uuid","required":true}],
      sql_template: `SELECT v2.id, v2.name, v2.name_full, v2.slug, v2.scu, v2.is_spaceship, v2.is_ground_vehicle, v2.is_concept
FROM vehicles v1
JOIN vehicles v2 ON v2.company_uex_id = v1.company_uex_id
WHERE v1.id = :vehicle_id
ORDER BY v2.name;`
    },
  ],
  notes: null
};

// ---------- provenance ----------
const provenance = {
  generated_at: new Date().toISOString(),
  kb_generator_workflow: 'JSONKB - Vehicles v1',
  game_version: row.game_version || raw.game_version || null,
  is_live_only: true,
};

// ---------- hash (FNV32 doubled => 16 hex chars) ----------
function fnv1a32Hex(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = (hash + ((hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24))) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}
function hash16(str) {
  const a = fnv1a32Hex(str);
  const b = fnv1a32Hex(str + '|v2');
  return a + b;
}

// ---------- JSONKB object ----------
const jsonkb = {
  kb_version: '1.0',

  entity_type: 'vehicle',
  entity_id: row.id || null,
  entity_slug: slug,
  entity_name: name,

  source: 'uex',
  source_id: row.source_id || (row.uex_vehicle_id != null ? `vehicles:${row.uex_vehicle_id}` : (row.source_id || null)),
  source_table: 'vehicles',

  kb_text,
  kb_links,
  entity_metadata,
  rag_hints,
  provenance,
};

const hashBasis = stableStringify({
  entity_type: jsonkb.entity_type,
  entity_id: jsonkb.entity_id,
  kb_text: jsonkb.kb_text,
  entity_metadata: jsonkb.entity_metadata,
  rag_hints: jsonkb.rag_hints,
});

jsonkb.provenance.content_hash = hash16(hashBasis);
// const hashBasis = `${jsonkb.entity_type}|${jsonkb.entity_id}|${jsonkb.kb_text}|${jsonkb.entity_metadata}`;
//jsonkb.provenance.content_hash = hash16(hashBasis);

// ---------- JSONKB file path ----------
const jsonkb_file_path = `/kb/vehicle/${slug}`;

return [
  {
    json: {
      vehicle_id: row.id,
      slug,
      name,
      jsonkb,
      jsonkb_file_path,
    },
  },
];

